"""Collect a FROZEN offline dataset from the two-route SWAMP env, generated by
the QUALIFIED gate-aware teacher (the confounded behavior policy).

This is the observational dataset for the confounding experiment: the teacher
reads the hidden swamp bits (all-clear -> shortcut; any active -> wait one step,
then clear -> shortcut else safe detour), so the DATA couples the hidden
confounder U to the route taken -- yet the learner observation is XY + goal only.

  obs         [N, L, 4]      learner obs = [x, y, goal_x, goal_y]   (NO swamp bits)
  act         [N, L, 2]      teacher/random action (float32; act[:,-1] dummy)
  swamp_bits  [N, L, 3]      AUDIT-ONLY: the 3 bits governing each step (uint8)
  route_label [N]            AUDIT-ONLY: 0 random, 1 immediate_shortcut,
                             2 wait_shortcut, 3 wait_detour, 4 other
  meta        json string    provenance + route-frequency summary

swamp_bits / route_label are recognized AUDIT keys (crl.offline_audit) so the
offline audit keeps them OUT of the learner namespace (G2/G6). A small fraction
of fully-random episodes is mixed in for state coverage. Output is frozen
(read-only) with a sha256 sidecar manifest.

Run:
  python -m scripts.collect_swamp_dataset --episodes 6000 --random_frac 0.2 \
      --teacher_noise 0.15 --seed 0 --out datasets/swamp_teacher_s0.npz
"""
import argparse
import hashlib
import json
import os

import numpy as np

from crl import envs as envs_mod
from crl.config import Config
from scripts.qualify_two_route_swamp import (
    make_teacher, classify_teacher, SWAMP, POST_CELL)

ROUTE_CODE = {'random': 0, 'immediate_shortcut': 1, 'wait_shortcut': 2,
              'wait_detour': 3, 'other': 4}

_MSWAMP = ((3, 3), (4, 3), (5, 3))     # swamp cells (matched setting helpers)
_MPOST = (6, 3)                        # first cell past the swamp


def _sha256(path, chunk=1 << 20):
  h = hashlib.sha256()
  with open(path, 'rb') as f:
    for b in iter(lambda: f.read(chunk), b''):
      h.update(b)
  return h.hexdigest()


def _cells(traj, walls):
  return [tuple(np.clip(np.floor(p).astype(int), [0, 0],
                        np.array(walls.shape) - 1)) for p in traj]


def collect(episodes, random_frac, teacher_noise, seed, out, force=False):
  if os.path.exists(out) and not force:
    raise SystemExit(f'REFUSING to overwrite frozen dataset {out} (use --force).')
  env_name = 'point_two_route_swamp_v0'
  cfg = Config(env_name=env_name)
  env = envs_mod.make_env(env_name, cfg, seed=seed)
  walls = env._walls
  teacher = make_teacher(env)
  rng = np.random.default_rng(seed)
  L = env.max_episode_steps + 1
  D, A = cfg.obs_dim + cfg.goal_dim, cfg.action_dim

  obs_out = np.zeros((episodes, L, D), np.float32)
  act_out = np.zeros((episodes, L, A), np.float32)
  bits_out = np.zeros((episodes, L, 3), np.uint8)
  route_out = np.zeros((episodes,), np.int64)
  n_random = int(round(episodes * random_frac))
  succ, slowed_short = [], []

  for ep in range(episodes):
    is_random = ep < n_random          # leading block; teacher/env are i.i.d.
    env.set_auto_resample(True)
    env.reset()                         # fixed start+goal; samples swamp bits
    g = env.goal.copy()
    memo = {}
    traj = [env.state.copy()]
    for t in range(env.max_episode_steps):
      obs_out[ep, t] = np.concatenate([env.state, g]).astype(np.float32)
      bits_out[ep, t] = env.swamp_bits.astype(np.uint8)   # bits for THIS step
      if is_random:
        a = rng.uniform(-1, 1, A).astype(np.float32)
      else:
        a = np.asarray(teacher(env.state.copy(), g, memo), np.float32)
        if teacher_noise > 0 and np.any(a != 0):           # jitter MOVES only
          a = np.clip(a + rng.normal(0, teacher_noise, A), -1, 1).astype(np.float32)
      act_out[ep, t] = a
      env.step(a)
      traj.append(env.state.copy())
    obs_out[ep, -1] = np.concatenate([env.state, g]).astype(np.float32)
    bits_out[ep, -1] = env.swamp_bits.astype(np.uint8)

    traj = np.array(traj)
    cells = _cells(traj, walls)
    entered = any(c in SWAMP for c in cells)
    crossed = entered and any(c == POST_CELL for c in cells)
    used_safe = bool(np.any(traj[:, 1] < 2.0))
    min_d = float(np.min(np.linalg.norm(traj - g, axis=1)))
    if is_random:
      route = 'random'
    else:
      route = classify_teacher(dict(crossed=crossed, used_safe=used_safe,
                                    n_waits=int(memo.get('n_waits', 0))))
      # count steps the teacher spent in an ACTIVE swamp cell (should be ~0)
      sl = sum(1 for t in range(env.max_episode_steps)
               if cells[t + 1] in SWAMP and bits_out[ep, t][SWAMP.index(cells[t + 1])])
      slowed_short.append(int(sl))
    route_out[ep] = ROUTE_CODE[route]
    succ.append(float(min_d < 0.5))
    if (ep + 1) % 500 == 0:
      print(f'  {ep + 1}/{episodes} (reached@0.5 {np.mean(succ):.3f})', flush=True)

  succ = np.asarray(succ)
  routes, counts = np.unique(route_out, return_counts=True)
  inv = {v: k for k, v in ROUTE_CODE.items()}
  route_freq = {inv[int(r)]: int(c) for r, c in zip(routes, counts)}
  meta = {
      'env_name': env_name, 'episodes': int(episodes), 'seed': int(seed),
      'behavior_policy': f'qualified_swamp_teacher (+random_frac={random_frac}, '
                         f'teacher_noise={teacher_noise})',
      'random_frac': float(random_frac), 'teacher_noise': float(teacher_noise),
      'obs_dim': int(cfg.obs_dim), 'goal_dim': int(cfg.goal_dim), 'action_dim': int(A),
      'max_episode_steps': int(env.max_episode_steps), 'episode_len_rows_L': int(L),
      'obs_width_D': int(D), 'n_transitions': int(episodes * (L - 1)),
      'route_label_code': ROUTE_CODE, 'route_frequencies': route_freq,
      'reached_0p5_rate': float(succ.mean()),
      'teacher_active_swamp_steps_total': int(np.sum(slowed_short)),
      'audit_fields': ['swamp_bits', 'route_label'],
      'note': 'swamp_bits/route_label are AUDIT-ONLY; learner obs is XY+goal only',
  }
  os.makedirs(os.path.dirname(out) or '.', exist_ok=True)
  np.savez(out, obs=obs_out, act=act_out, swamp_bits=bits_out,
           route_label=route_out, meta=np.array(json.dumps(meta)))
  digest = _sha256(out)
  manifest = dict(path=os.path.abspath(out), sha256=digest,
                  size_bytes=int(os.path.getsize(out)),
                  obs_shape=list(obs_out.shape), act_shape=list(act_out.shape),
                  audit_shapes={'swamp_bits': list(bits_out.shape),
                                'route_label': list(route_out.shape)},
                  frozen=True, meta=meta)
  json.dump(manifest, open(out + '.manifest.json', 'w'), indent=2)
  try:
    os.chmod(out, 0o444)
  except OSError:
    pass
  print(f'\nFROZEN swamp dataset -> {out} ({os.path.getsize(out)/1e6:.1f} MB)')
  print(f'sha256 = {digest}')
  print(json.dumps(meta, indent=2))
  return manifest


# --------------------------------------------------------------------------- #
# MiniGrid-matched setting                                                     #
# --------------------------------------------------------------------------- #
MATCHED_TEACHER_MODE = {'random': 0, 'forced_safe': 1, 'immediate_shortcut': 2,
                        'wait_shortcut': 3}
MATCHED_ROUTE_CODE = {'random': 0, 'shortcut': 1, 'safe_detour': 2, 'other': 3}


def collect_matched(episodes, random_frac, teacher_noise, seed, out,
                    force=False, force_safe_prob=0.05,
                    env_name='point_two_route_swamp_matched_v0'):
  """MiniGrid-matched dataset: matched teacher (force_safe_prob force-safe,
  wait-until-clear, p=0.10) + random coverage. Records the extended audit
  fields. force_safe_prob controls SAFE-ROUTE COVERAGE: the Manski lower
  bound can only certify alternatives the behavior policy actually covers
  coherently (no data => no certificate), so causal-arm datasets need it
  well above the 0.05 qualification default."""
  from scripts.qualify_two_route_swamp_matched import (
      make_matched_teacher, rollout_matched)
  if os.path.exists(out) and not force:
    raise SystemExit(f'REFUSING to overwrite frozen dataset {out} (use --force).')
  cfg = Config(env_name=env_name)
  env = envs_mod.make_env(env_name, cfg, seed=seed)
  rng = np.random.default_rng(seed)
  teacher = make_matched_teacher(env, rng, force_safe_prob=force_safe_prob)
  L = env.max_episode_steps + 1
  D, A = cfg.obs_dim + cfg.goal_dim, cfg.action_dim

  obs_out = np.zeros((episodes, L, D), np.float32)
  act_out = np.zeros((episodes, L, A), np.float32)
  bits_out = np.zeros((episodes, L, 3), np.uint8)
  route_out = np.zeros((episodes,), np.int64)
  mode_out = np.zeros((episodes,), np.int64)
  fsafe_out = np.zeros((episodes,), np.uint8)
  wait_out = np.zeros((episodes,), np.int64)
  entered_out = np.zeros((episodes,), np.uint8)
  n_random = int(round(episodes * random_frac))
  succ = []

  for ep in range(episodes):
    is_random = ep < n_random
    if is_random:
      env.set_auto_resample(True)
      env.reset()
      g = env.goal.copy()
      traj = [env.state.copy()]
      for t in range(env.max_episode_steps):
        obs_out[ep, t] = np.concatenate([env.state, g]).astype(np.float32)
        bits_out[ep, t] = env.swamp_bits.astype(np.uint8)
        a = rng.uniform(-1, 1, A).astype(np.float32)
        act_out[ep, t] = a
        env.step(a)
        traj.append(env.state.copy())
      obs_out[ep, -1] = np.concatenate([env.state, g]).astype(np.float32)
      bits_out[ep, -1] = env.swamp_bits.astype(np.uint8)
      traj = np.array(traj)
      cells = _cells(traj, env._walls)
      mode_out[ep] = MATCHED_TEACHER_MODE['random']
      route_out[ep] = MATCHED_ROUTE_CODE['random']
      entered_out[ep] = int(any(
          cells[t + 1] in _MSWAMP and bits_out[ep, t][_MSWAMP.index(cells[t + 1])]
          for t in range(len(cells) - 1)))
      succ.append(float(np.min(np.linalg.norm(traj - g, axis=1)) < 0.5))
    else:
      # replay the matched teacher, recording obs/act inline (with noise on moves)
      env.set_auto_resample(True)
      env.reset()
      g = env.goal.copy()
      memo = {}
      traj = [env.state.copy()]
      for t in range(env.max_episode_steps):
        obs_out[ep, t] = np.concatenate([env.state, g]).astype(np.float32)
        bits_out[ep, t] = env.swamp_bits.astype(np.uint8)
        a = np.asarray(teacher(env.state.copy(), g, memo), np.float32)
        if teacher_noise > 0 and np.any(a != 0):
          a = np.clip(a + rng.normal(0, teacher_noise, A), -1, 1).astype(np.float32)
        act_out[ep, t] = a
        env.step(a)
        traj.append(env.state.copy())
      obs_out[ep, -1] = np.concatenate([env.state, g]).astype(np.float32)
      bits_out[ep, -1] = env.swamp_bits.astype(np.uint8)
      traj = np.array(traj)
      cells = _cells(traj, env._walls)
      crossed = any(c == _MPOST for c in cells)
      used_safe = bool(np.any(traj[:, 1] < 2.0))
      mode_out[ep] = MATCHED_TEACHER_MODE.get(memo.get('teacher_mode', 'other'),
                                              MATCHED_TEACHER_MODE['immediate_shortcut'])
      route_out[ep] = MATCHED_ROUTE_CODE['shortcut'] if crossed else (
          MATCHED_ROUTE_CODE['safe_detour'] if used_safe else MATCHED_ROUTE_CODE['other'])
      fsafe_out[ep] = int(memo.get('force_safe', False))
      wait_out[ep] = int(memo.get('wait_count', 0))
      entered_out[ep] = int(any(
          cells[t + 1] in _MSWAMP and bits_out[ep, t][_MSWAMP.index(cells[t + 1])]
          for t in range(len(cells) - 1)))
      succ.append(float(np.min(np.linalg.norm(traj - g, axis=1)) < 0.5))
    if (ep + 1) % 500 == 0:
      print(f'  {ep + 1}/{episodes} (reached@0.5 {np.mean(succ):.3f})', flush=True)

  succ = np.asarray(succ)
  inv_mode = {v: k for k, v in MATCHED_TEACHER_MODE.items()}
  modes, counts = np.unique(mode_out, return_counts=True)
  mode_freq = {inv_mode[int(m)]: int(c) for m, c in zip(modes, counts)}
  meta = {
      'env_name': env_name, 'setting': 'minigrid_matched',
      'episodes': int(episodes), 'seed': int(seed),
      'behavior_policy': f'minigrid_matched_teacher(force_safe={force_safe_prob}, '
                         f'wait_until_clear) + random_frac={random_frac}, '
                         f'teacher_noise={teacher_noise}',
      'random_frac': float(random_frac), 'teacher_noise': float(teacher_noise),
      'per_cell_swamp_prob': 0.10, 'force_safe_prob': float(force_safe_prob),
      'obs_dim': int(cfg.obs_dim), 'goal_dim': int(cfg.goal_dim), 'action_dim': int(A),
      'max_episode_steps': int(env.max_episode_steps), 'episode_len_rows_L': int(L),
      'obs_width_D': int(D), 'n_transitions': int(episodes * (L - 1)),
      'teacher_mode_code': MATCHED_TEACHER_MODE, 'route_label_code': MATCHED_ROUTE_CODE,
      'teacher_mode_frequencies': mode_freq,
      'forced_safe_rate': float(fsafe_out[n_random:].mean()) if episodes > n_random else None,
      'reached_0p5_rate': float(succ.mean()),
      'teacher_active_swamp_entries': int(entered_out[n_random:].sum()),
      'audit_fields': ['swamp_bits', 'route_label', 'teacher_mode', 'force_safe',
                       'wait_count', 'entered_active_swamp'],
      'note': 'all audit fields are AUDIT-ONLY; learner obs is [x,y,gx,gy] only',
  }
  os.makedirs(os.path.dirname(out) or '.', exist_ok=True)
  np.savez(out, obs=obs_out, act=act_out, swamp_bits=bits_out,
           route_label=route_out, teacher_mode=mode_out, force_safe=fsafe_out,
           wait_count=wait_out, entered_active_swamp=entered_out,
           meta=np.array(json.dumps(meta)))
  digest = _sha256(out)
  manifest = dict(path=os.path.abspath(out), sha256=digest,
                  size_bytes=int(os.path.getsize(out)),
                  obs_shape=list(obs_out.shape), act_shape=list(act_out.shape),
                  audit_shapes={'swamp_bits': list(bits_out.shape),
                                'route_label': list(route_out.shape),
                                'teacher_mode': list(mode_out.shape),
                                'force_safe': list(fsafe_out.shape),
                                'wait_count': list(wait_out.shape),
                                'entered_active_swamp': list(entered_out.shape)},
                  frozen=True, meta=meta)
  json.dump(manifest, open(out + '.manifest.json', 'w'), indent=2)
  try:
    os.chmod(out, 0o444)
  except OSError:
    pass
  print(f'\nFROZEN matched dataset -> {out} ({os.path.getsize(out)/1e6:.1f} MB)')
  print(f'sha256 = {digest}')
  print(json.dumps(meta, indent=2))
  return manifest


def main():
  p = argparse.ArgumentParser(description=__doc__.splitlines()[0])
  p.add_argument('--setting', default='strong',
                 choices=['strong', 'minigrid_matched'])
  p.add_argument('--episodes', type=int, default=6000)
  p.add_argument('--random_frac', type=float, default=0.2)
  p.add_argument('--teacher_noise', type=float, default=0.15)
  p.add_argument('--force_safe_prob', type=float, default=0.05,
                 help='matched setting only: safe-route coverage rate')
  p.add_argument('--env_name', default='point_two_route_swamp_matched_v0',
                 help='matched setting only: e.g. point_two_route_swamp_v0 '
                      'runs the wait-teacher on the STRONG env (p=0.2)')
  p.add_argument('--seed', type=int, default=0)
  p.add_argument('--out', required=True)
  p.add_argument('--force', action='store_true')
  a = p.parse_args()
  if a.force and os.path.exists(a.out):
    try:
      os.chmod(a.out, 0o644)
    except OSError:
      pass
  if a.setting == 'minigrid_matched':
    collect_matched(a.episodes, a.random_frac, a.teacher_noise, a.seed, a.out,
                    force=a.force, force_safe_prob=a.force_safe_prob,
                    env_name=a.env_name)
  else:
    collect(a.episodes, a.random_frac, a.teacher_noise, a.seed, a.out, force=a.force)


if __name__ == '__main__':
  main()
